import{_ as t,o as e,c as a,ag as l}from"./chunks/framework.eQLvDOR_.js";const b=JSON.parse('{"title":"notebooklm-rag-orchestration","description":"","frontmatter":{"title":"notebooklm-rag-orchestration","concept":"NotebookLM RAG 编排模式","concept_id":"notebooklm-rag-orchestration","aliases":["TAP-Model","Teacher-Assistant-Principal"],"sources":["02_Library/NotebookLM_Workflows/[NotebookLM_Workflows] 用好 NotebookLM 立省 80 Token.md"],"related_concepts":["[[context-optimization]]","[[augmented-llm]]"],"created_at":"2026-04-21","last_compiled":"2026-04-21"},"headers":[],"relativePath":"wiki/concepts/notebooklm-rag-orchestration.md","filePath":"wiki/concepts/notebooklm-rag-orchestration.md","lastUpdated":null}'),r={name:"wiki/concepts/notebooklm-rag-orchestration.md"};function i(n,o,s,c,h,d){return e(),a("div",null,[...o[0]||(o[0]=[l('<h1 id="notebooklm-rag-编排模式-tap-模型" tabindex="-1">NotebookLM RAG 编排模式 (TAP 模型) <a class="header-anchor" href="#notebooklm-rag-编排模式-tap-模型" aria-label="Permalink to &quot;NotebookLM RAG 编排模式 (TAP 模型)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>一种通过解耦“重数据检索”与“逻辑推理”来优化 Token 成本的工作流模型。核心思想是让 <strong>NotebookLM</strong> 充当领域专家库，而 <strong>Claude</strong> 充当任务执行者。</p><h2 id="tap-三要素模型" tabindex="-1">TAP 三要素模型 <a class="header-anchor" href="#tap-三要素模型" aria-label="Permalink to &quot;TAP 三要素模型&quot;">​</a></h2><ul><li><strong>Teacher (老师) — NotebookLM</strong>: <ul><li>负责存储海量语料（论文、文档、日志）。</li><li>提供带引用的 RAG 检索。</li><li>角色是“只读咨询台”，不参与代码编写或环境操作。</li></ul></li><li><strong>Assistant (助手) — Claude</strong>: <ul><li>负责逻辑推理、编排工具、执行 Action。</li><li>不懂就去问“老师”，只摄入经过 RAG 蒸馏后的几百字答案。</li><li>角色是“课题执行人”。</li></ul></li><li><strong>Principal (委托人) — 用户</strong>: <ul><li>负责配置知识边界（初始化 Notebook）。</li><li>仅在关键决策点介入。</li></ul></li></ul><h2 id="核心价值" tabindex="-1">核心价值 <a class="header-anchor" href="#核心价值" aria-label="Permalink to &quot;核心价值&quot;">​</a></h2><ol><li><strong>常数级成本</strong>：传统模式（Context Stuffing）成本随语料大小线性增长；TAP 模式下，Claude 只看到 RAG 结果，成本近乎恒定且极低。</li><li><strong>规避 TTL 限制</strong>：Anthropic 的 Prompt Cache 有 1 小时失效限制，研究场景（思考久、问答慢）命中率低。NotebookLM 的索引永久在线且对用户免费。</li><li><strong>事实溯源</strong>：强制要求助手保留 [1][2] 引用，防止 AI 在长文本中产生幻觉。</li></ol><h2 id="典型场景" tabindex="-1">典型场景 <a class="header-anchor" href="#典型场景" aria-label="Permalink to &quot;典型场景&quot;">​</a></h2><ul><li><strong>学术调研</strong>：47 篇论文灌入 NotebookLM，Claude 负责总结对比。</li><li><strong>财务审计/打新</strong>：同时分析 8 家公司的招股书，生成对比决策表。</li><li><strong>故障排查</strong>：大量历史日志灌入 NotebookLM，Claude 负责根据异常片段写修复脚本。</li></ul><hr><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>在 Claude Code 中安装 <code>notebooklm-client</code> 后，配置如下指令：</p><blockquote><p>“任何涉及论文观点的问题，优先调用 <code>/notecraft chat</code> 问老师，不要凭记忆回答，也不要让我贴入原文。”</p></blockquote><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/NotebookLM_Workflows/NotebookLM_Workflows - 用好 NotebookLM 立省 80 Token.html">[NotebookLM_Workflows] 用好 NotebookLM 立省 80 Token</a></li></ul>',16)])])}const u=t(r,[["render",i]]);export{b as __pageData,u as default};
